import{_ as s,c as a,G as n,b as e}from"./chunks/framework.DvhYz0iE.js";const p=JSON.parse('{"title":"集创赛CPU有关笔记","description":"这篇文章是有关于集创赛CPU设计的笔记。","frontmatter":{"title":"集创赛CPU有关笔记","tags":["笔记"],"categories":["笔记"],"date":"2026-07-07T00:00:00.000Z","description":"这篇文章是有关于集创赛CPU设计的笔记。","articleGPT":"这篇文章是有关于集创赛CPU设计的笔记。","references":[{"title":"CPU代码仓库","url":"https://github.com/Stomatra/RV32Final"}],"head":[["link",{"rel":"canonical","href":"https://rinyuki.com/posts/2026/0707"}]]},"headers":[],"relativePath":"posts/2026/0707.md","filePath":"posts/2026/0707.md","lastUpdated":null}');const l=s({name:"posts/2026/0707.md"},[["render",function(s,p,l,i,r,t){return e(),a("div",null,p[0]||(p[0]=[n('<h1 id="集创赛cpu有关笔记" tabindex="-1">集创赛CPU有关笔记 <a class="header-anchor" href="#集创赛cpu有关笔记" aria-label="Permalink to &quot;集创赛CPU有关笔记&quot;">​</a></h1><h2 id="_7月7日更新" tabindex="-1">7月7日更新 <a class="header-anchor" href="#_7月7日更新" aria-label="Permalink to &quot;7月7日更新&quot;">​</a></h2><h2 id="cpu代码仓库" tabindex="-1">CPU代码仓库： <a class="header-anchor" href="#cpu代码仓库" aria-label="Permalink to &quot;CPU代码仓库：&quot;">​</a></h2><p><a href="https://github.com/Stomatra/RV32Final" target="_blank" rel="noreferrer">https://github.com/Stomatra/RV32Final</a></p><h2 id="cpu工程基本结构" tabindex="-1">CPU工程基本结构 <a class="header-anchor" href="#cpu工程基本结构" aria-label="Permalink to &quot;CPU工程基本结构&quot;">​</a></h2><p>myCPU的外部接口：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>//IROM 取指接口</span></span>\n<span class="line"><span>output logic [11:0]  irom_addr,//CPU 当前要取的指令</span></span>\n<span class="line"><span>input  logic [31:0]  irom_data,//IROM 返回的 32 位指令</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>//perip 数据/外设访问接口</span></span>\n<span class="line"><span>output logic [31:0]  perip_addr,//load/store 访问的数据地址</span></span>\n<span class="line"><span>output logic         perip_wen,//是否写</span></span>\n<span class="line"><span>output logic [1:0]   perip_mask,//写字节/半字/字</span></span>\n<span class="line"><span>output logic [31:0]  perip_wdata,//写入数据</span></span>\n<span class="line"><span>input  logic [31:0]  perip_rdata//读回数据</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>CPU的五个阶段（五级流水线）：</p><p>IF ：取指</p><p>ID ：译码 + 读寄存器，只决定“这条指令要干什么”</p><p>EX ：执行 ALU / 分支 / CSR / M扩展 / trap 为真正计算的阶段</p><p>MEM ：访存</p><p>WB ：写回寄存器，写回 x0~x31</p><h3 id="if-阶段" tabindex="-1">IF 阶段 <a class="header-anchor" href="#if-阶段" aria-label="Permalink to &quot;IF 阶段&quot;">​</a></h3><p><strong>IF 阶段主要是取指阶段，主要是从 IROM 中取出指令，计算下一条指令的地址。</strong></p><p>核心寄存器：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>logic [31:0] pc_q;</span></span>\n<span class="line"><span>logic [31:0] pc_next;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>PC更新逻辑：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// IF 级 PC 更新优先级：redirect &gt; stall/hold &gt; 顺序 +4。</span></span>\n<span class="line"><span>always_comb begin</span></span>\n<span class="line"><span>\tif (ex_pc_redirect) begin</span></span>\n<span class="line"><span>\t\t//如果 EX 阶段要求跳转，PC = 跳转目标</span></span>\n<span class="line"><span>\t\t//包括：branch_taken jal jalr ecall mret mul_helper</span></span>\n<span class="line"><span>\t\tpc_next = ex_pc_target;</span></span>\n<span class="line"><span>\tend else if (load_use_hazard || pc_ex_hazard || pc_mem_hazard || mem_load_stall || m_stall) begin</span></span>\n<span class="line"><span>\t\t//如果存在相关冒险或停顿，PC 保持不变</span></span>\n<span class="line"><span>\t\tpc_next = pc_q;</span></span>\n<span class="line"><span>\tend else begin</span></span>\n<span class="line"><span>\t\t//顺序执行，PC + 4</span></span>\n<span class="line"><span>\t\tpc_next = pc_q + 32&#39;d4;</span></span>\n<span class="line"><span>\tend</span></span>\n<span class="line"><span>end</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>// IF 级 PC 寄存器，在 reset 时初始化为 RESET_PC。</span></span>\n<span class="line"><span>always_ff @(posedge cpu_clk or posedge cpu_rst) begin</span></span>\n<span class="line"><span>\tif (cpu_rst) begin</span></span>\n<span class="line"><span>\t\tpc_q &lt;= RESET_PC;</span></span>\n<span class="line"><span>\tend else begin</span></span>\n<span class="line"><span>\t\tpc_q &lt;= pc_next;</span></span>\n<span class="line"><span>\tend</span></span>\n<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><p>IF/ID 寄存器负责把当前取到的指令送到 ID 阶段：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ifid_pc    &lt;= pc_q;</span></span>\n<span class="line"><span>ifid_instr &lt;= irom_data;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>但遇到 load hazard、mem stall、div stall 时会保持。</p><h3 id="id-阶段" tabindex="-1">ID 阶段 <a class="header-anchor" href="#id-阶段" aria-label="Permalink to &quot;ID 阶段&quot;">​</a></h3><p><strong>ID 阶段主要是指令译码阶段，负责解析指令的操作类型、操作数以及目标寄存器。ID 阶段还会读取寄存器文件中的源操作数，并生成控制信号供后续阶段使用。</strong></p><p>ID 阶段主要干三件事：</p><ol><li>从指令中拆出 opcode / rd / rs1 / rs2 / funct3 / funct7</li></ol><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>assign opcode = instr[6:0];</span></span>\n<span class="line"><span>assign rd     = instr[11:7];</span></span>\n<span class="line"><span>assign funct3 = instr[14:12];</span></span>\n<span class="line"><span>assign rs1    = instr[19:15];</span></span>\n<span class="line"><span>assign rs2    = instr[24:20];</span></span>\n<span class="line"><span>assign funct7 = instr[31:25];</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><ol start="2"><li>从寄存器堆读取 rs1 / rs2</li><li>根据 opcode 生成控制信号</li></ol><p>ID 阶段的主控制器就是这个大 always_comb：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>always_comb begin</span></span>\n<span class="line"><span>    id_uses_rs1      = 1&#39;b0;</span></span>\n<span class="line"><span>    id_uses_rs2      = 1&#39;b0;</span></span>\n<span class="line"><span>    id_rf_we         = 1&#39;b0;</span></span>\n<span class="line"><span>    id_wb_sel        = WB_SRC_ALU;</span></span>\n<span class="line"><span>    ...</span></span>\n<span class="line"><span>    if (ifid_valid) begin</span></span>\n<span class="line"><span>        case (id_opcode)</span></span>\n<span class="line"><span>            ...</span></span>\n<span class="line"><span>        endcase</span></span>\n<span class="line"><span>    end</span></span>\n<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>这段负责告诉后面的流水线：</p><ul><li>这条指令用不用 rs1</li><li>用不用 rs2</li><li>写不写 rd</li><li>写回来源是什么</li><li>ALU 做什么</li><li>是不是访存</li><li>是不是 CSR</li><li>是不是 M 扩展</li></ul><h3 id="id-ex-流水寄存器" tabindex="-1">ID/EX 流水寄存器 <a class="header-anchor" href="#id-ex-流水寄存器" aria-label="Permalink to &quot;ID/EX 流水寄存器&quot;">​</a></h3><p><strong>把指令信息送到 EX。ID 阶段译码后，不能直接执行，而是存入 ID/EX 寄存器。</strong></p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>always_ff @(posedge cpu_clk or posedge cpu_rst) begin</span></span>\n<span class="line"><span>\t\tif (cpu_rst) begin</span></span>\n<span class="line"><span>\t\t\tidex_valid         &lt;= 1&#39;b0;</span></span>\n<span class="line"><span>\t\t\tidex_pc            &lt;= 32&#39;h0;</span></span>\n<span class="line"><span>\t\t\tidex_rs1           &lt;= 5&#39;h0;</span></span>\n<span class="line"><span>\t\t\tidex_rs2           &lt;= 5&#39;h0;</span></span>\n<span class="line"><span>            ...</span></span>\n<span class="line"><span>\t\tend else if (mem_load_stall || m_stall) begin</span></span>\n<span class="line"><span>\t\t\t// hold IDEX - memory read stall</span></span>\n<span class="line"><span>\t\tend else if (ex_pc_redirect || load_use_hazard || pc_ex_hazard || pc_mem_hazard) begin</span></span>\n<span class="line"><span>\t\t\tidex_valid         &lt;= 1&#39;b0;</span></span>\n<span class="line"><span>\t\t\tidex_pc            &lt;= 32&#39;h0;</span></span>\n<span class="line"><span>\t\t\tidex_rs1           &lt;= 5&#39;h0;</span></span>\n<span class="line"><span>\t\t\tidex_rs2           &lt;= 5&#39;h0;</span></span>\n<span class="line"><span>            ...</span></span>\n<span class="line"><span>\t\tend else if (id_mul_helper_hit) begin</span></span>\n<span class="line"><span>\t\t\tidex_valid         &lt;= 1&#39;b1;</span></span>\n<span class="line"><span>\t\t\tidex_pc            &lt;= ifid_pc;</span></span>\n<span class="line"><span>\t\t\tidex_rs1           &lt;= 5&#39;h0;</span></span>\n<span class="line"><span>\t\t\tidex_rs2           &lt;= 5&#39;h0;</span></span>\n<span class="line"><span>            ...</span></span>\n<span class="line"><span>\t\tend else begin</span></span>\n<span class="line"><span>\t\t\tidex_valid         &lt;= ifid_valid;</span></span>\n<span class="line"><span>\t\t\tidex_pc            &lt;= ifid_pc;</span></span>\n<span class="line"><span>\t\t\tidex_rs1           &lt;= id_rs1;</span></span>\n<span class="line"><span>\t\t\tidex_rs2           &lt;= id_rs2;</span></span>\n<span class="line"><span>            ...</span></span>\n<span class="line"><span>\t\tend</span></span>\n<span class="line"><span>\tend</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br></div></div><p>它的作用是：</p><p>ID 阶段：这条指令要干什么</p><p>ID/EX 保存：下一拍 EX 阶段照着这些信号执行</p><p>遇到 flush 时，这些信号会被清零。遇到 <code>mem_load_stall || div_stall</code> 时，ID/EX 会保持不动。</p><h3 id="ex-阶段" tabindex="-1">EX 阶段 <a class="header-anchor" href="#ex-阶段" aria-label="Permalink to &quot;EX 阶段&quot;">​</a></h3><p><strong>EX 阶段主要是执行阶段，负责进行算术运算、逻辑运算、分支判断等操作。EX 阶段会根据 ID 阶段传递过来的控制信号和操作数，执行相应的操作，并将结果传递给 MEM 阶段。</strong></p><p>目前EX阶段主要负责：</p><ul><li>ALU 运算</li><li>branch 判断</li><li>jal/jalr 目标地址</li><li>CSR 读写计算</li><li>ecall/mret trap 跳转</li><li>RV32M 乘除法结果选择</li><li>store 写数据准备</li></ul><h4 id="alu-输入选择" tabindex="-1">ALU 输入选择 <a class="header-anchor" href="#alu-输入选择" aria-label="Permalink to &quot;ALU 输入选择&quot;">​</a></h4><p>EX 阶段先通过前递逻辑得到 <code>ex_rs1_val</code> 和 <code>ex_rs2_val</code>。</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if (ex_fwd_rs1_from_exmem) begin</span></span>\n<span class="line"><span>    ex_rs1_val = exmem_wb_data;</span></span>\n<span class="line"><span>end else if (ex_fwd_rs1_from_memwb) begin</span></span>\n<span class="line"><span>    ex_rs1_val = memwb_wdata;</span></span>\n<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h4 id="alu-运算" tabindex="-1">ALU 运算 <a class="header-anchor" href="#alu-运算" aria-label="Permalink to &quot;ALU 运算&quot;">​</a></h4><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ALU #(32) u_alu (</span></span>\n<span class="line"><span>    .A(ex_alu_a),</span></span>\n<span class="line"><span>    .B(ex_alu_b),</span></span>\n<span class="line"><span>    .ALUOp(idex_alu_op),</span></span>\n<span class="line"><span>    .Result(ex_alu_y)</span></span>\n<span class="line"><span>);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>普通 RV32I 的 ADD、SUB、AND、OR、XOR、SLT、SLL、SRL、SRA 都走这里。</p><h4 id="分支和跳转" tabindex="-1">分支和跳转 <a class="header-anchor" href="#分支和跳转" aria-label="Permalink to &quot;分支和跳转&quot;">​</a></h4><p>分支比较在 EX 阶段做：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if (idex_pc_sel == PC_SRC_BRANCH) begin</span></span>\n<span class="line"><span>    ex_cmp_eq = (ex_pc_rs1_val == ex_pc_rs2_val);</span></span>\n<span class="line"><span>    ex_cmp_lt_signed = ($signed(ex_pc_rs1_val) &lt; $signed(ex_pc_rs2_val));</span></span>\n<span class="line"><span>    ex_cmp_lt_unsigned = (ex_pc_rs1_val &lt; ex_pc_rs2_val);</span></span>\n<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>然后根据 BEQ/BNE/BLT/BGE 等决定 <code>ex_br_take</code>。</p><p>PC 跳转目标统一由 <code>ex_pc_target</code> 给出：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if (ex_trap_redirect) begin</span></span>\n<span class="line"><span>    ex_pc_target = ex_trap_target;</span></span>\n<span class="line"><span>end else if (idex_mul_helper) begin</span></span>\n<span class="line"><span>    ex_pc_target = idex_mul_helper_ra;</span></span>\n<span class="line"><span>end else begin</span></span>\n<span class="line"><span>    case (idex_pc_sel)</span></span>\n<span class="line"><span>        PC_SRC_BRANCH: ex_pc_target = ex_br_take ? ex_pc_plus_imm : ex_pc4;</span></span>\n<span class="line"><span>        PC_SRC_JAL:    ex_pc_target = ex_pc_plus_imm;</span></span>\n<span class="line"><span>        PC_SRC_JALR:   ex_pc_target = ex_jalr_target;</span></span>\n<span class="line"><span>        default:       ex_pc_target = ex_pc4;</span></span>\n<span class="line"><span>    endcase</span></span>\n<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>真正决定要不要跳的是 <code>ex_pc_redirect</code>：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if (ex_trap_enter || ex_trap_return) begin</span></span>\n<span class="line"><span>    ex_pc_redirect = 1&#39;b1;</span></span>\n<span class="line"><span>end else if (idex_mul_helper) begin</span></span>\n<span class="line"><span>    ex_pc_redirect = 1&#39;b1;</span></span>\n<span class="line"><span>end else begin</span></span>\n<span class="line"><span>    case (idex_pc_sel)</span></span>\n<span class="line"><span>        PC_SRC_BRANCH: if (ex_br_take) ex_pc_redirect = 1&#39;b1;</span></span>\n<span class="line"><span>        PC_SRC_JAL:    ex_pc_redirect = 1&#39;b1;</span></span>\n<span class="line"><span>        PC_SRC_JALR:   ex_pc_redirect = 1&#39;b1;</span></span>\n<span class="line"><span>    endcase</span></span>\n<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>一句话：所有改变 PC 的东西，最后都归到 <code>ex_pc_redirect</code> + <code>ex_pc_target</code></p><h3 id="mem-阶段" tabindex="-1">MEM 阶段 <a class="header-anchor" href="#mem-阶段" aria-label="Permalink to &quot;MEM 阶段&quot;">​</a></h3><p><strong>MEM 阶段主要是访存阶段，负责对数据存储器进行读写操作。MEM 阶段会根据 EX 阶段传递过来的控制信号和地址，进行相应的访存操作，并将结果传递给 WB 阶段。</strong></p><p>load/store 不直接访问 DRAM，而是通过 <code>perip_bridge</code>。</p><p>CPU 对外的访存接口是：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>assign perip_addr  = exmem_alu_y;</span></span>\n<span class="line"><span>assign perip_wen   = exmem_valid &amp;&amp; exmem_mem_req &amp;&amp; exmem_mem_write;</span></span>\n<span class="line"><span>assign perip_mask  = exmem_mem_mask;</span></span>\n<span class="line"><span>assign perip_wdata = exmem_store_data;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>`perip_bridge` 里面把地址分成：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>```SystemVerilog</span></span>\n<span class="line"><span>DRAM：0x8010_0000 ~ 0x8013_FFFF</span></span>\n<span class="line"><span>SW0 ：0x8020_0000</span></span>\n<span class="line"><span>SW1 ：0x8020_0004</span></span>\n<span class="line"><span>KEY ：0x8020_0010</span></span>\n<span class="line"><span>SEG ：0x8020_0020</span></span>\n<span class="line"><span>LED ：0x8020_0040</span></span>\n<span class="line"><span>CNT ：0x8020_0050</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><p>这些地址在 <code>perip_bridge.sv</code> 里定义。</p><p>外设桥里所有读源都统一打一拍，因此 CPU 这边每次 load 会插入 <code>mem_load_stall</code>。<code>perip_bridge</code> 注释里明确写了 CPU 看到的 <code>perip_rdata</code> 是“地址给出后一拍有效”。</p><p>所以 CPU 里有：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>assign mem_load_stall = exmem_valid &amp;&amp; exmem_mem_req &amp;&amp; !exmem_mem_write &amp;&amp; !mem_stall_flag;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>意思是：</p><p>每遇到 load，额外停一拍，等 <code>perip_rdata</code> 稳定</p><h3 id="wb-阶段" tabindex="-1">WB 阶段 <a class="header-anchor" href="#wb-阶段" aria-label="Permalink to &quot;WB 阶段&quot;">​</a></h3><p><strong>WB 阶段主要负责将计算结果或访存结果写回寄存器文件。</strong></p><p>MEM 阶段之后，结果进入 MEM/WB。</p><p>最终写回 RF 的是：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.wen   (memwb_rf_we &amp;&amp; memwb_valid),</span></span>\n<span class="line"><span>.waddr (memwb_rd),</span></span>\n<span class="line"><span>.wdata (memwb_wdata)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>mem_wb_data</code> 的选择是：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>assign mem_wb_data = (exmem_wb_sel == WB_SRC_MEM) ? mem_load_data : exmem_wb_data;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>也就是说：</p><p>如果是 load，写回 <code>perip_rdata</code> 处理后的数据，否则，写回 EX 阶段已经算好的 <code>exmem_wb_data</code>。</p><p><strong>这个 CPU 的主线就是：PC 取指 → ID 译码生成控制信号 → ID/EX 保存 → EX 执行 ALU/CSR/trap/RV32M → EX/MEM 访存或传递结果 → MEM/WB 写回寄存器。</strong></p><h2 id="重要变量" tabindex="-1">重要变量 <a class="header-anchor" href="#重要变量" aria-label="Permalink to &quot;重要变量&quot;">​</a></h2><h2 id="rd" tabindex="-1">rd <a class="header-anchor" href="#rd" aria-label="Permalink to &quot;rd&quot;">​</a></h2><p><strong>rd 是指令的目标寄存器编号，位于指令的 [11:7] 位。它表示当前指令执行后，结果将写入哪个寄存器。</strong></p><h2 id="rs1" tabindex="-1">rs1 <a class="header-anchor" href="#rs1" aria-label="Permalink to &quot;rs1&quot;">​</a></h2><p><strong>rs1 是指令的第一个源寄存器编号，位于指令的 [19:15] 位。它表示当前指令需要读取的第一个操作数所在的寄存器。</strong></p><h2 id="rs2" tabindex="-1">rs2 <a class="header-anchor" href="#rs2" aria-label="Permalink to &quot;rs2&quot;">​</a></h2><p><strong>rs2 是指令的第二个源寄存器编号，位于指令的 [24:20] 位。它表示当前指令需要读取的第二个操作数所在的寄存器。</strong></p><h2 id="funct3" tabindex="-1">funct3 <a class="header-anchor" href="#funct3" aria-label="Permalink to &quot;funct3&quot;">​</a></h2><p><strong>funct3 是指令的功能码，位于指令的 [14:12] 位。它用于区分同一类指令的不同操作，例如在 ALU 指令中，funct3 可以表示加法、减法、与、或等操作。</strong></p><h2 id="funct7" tabindex="-1">funct7 <a class="header-anchor" href="#funct7" aria-label="Permalink to &quot;funct7&quot;">​</a></h2><p><strong>funct7 是指令的功能扩展码，位于指令的 [31:25] 位。它用于进一步区分同一类指令的不同操作，通常与 funct3 结合使用，以确定具体的操作类型。</strong></p><h2 id="opcode" tabindex="-1">opcode <a class="header-anchor" href="#opcode" aria-label="Permalink to &quot;opcode&quot;">​</a></h2><p><strong>opcode 是指令的操作码，位于指令的 [6:0] 位。它用于确定指令的类型和操作类别，例如 ALU 指令、跳转指令、访存指令等。</strong></p><h2 id="冒险处理" tabindex="-1">冒险处理 <a class="header-anchor" href="#冒险处理" aria-label="Permalink to &quot;冒险处理&quot;">​</a></h2><h3 id="普通alu运算冒险" tabindex="-1">普通ALU运算冒险 <a class="header-anchor" href="#普通alu运算冒险" aria-label="Permalink to &quot;普通ALU运算冒险&quot;">​</a></h3><h4 id="前递" tabindex="-1">前递 <a class="header-anchor" href="#前递" aria-label="Permalink to &quot;前递&quot;">​</a></h4><p><strong>前递（forwarding）是解决数据冒险的一种方法，通过将尚未写回寄存器文件的结果直接传递给需要使用该结果的指令，从而避免等待写回阶段。</strong></p><p>假设有两条指令：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x3, x1, x2</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">sub</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x4, x3, x5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>当 <code>sub</code> 指令到达 EX 阶段时，<code>x3</code> 的值还没有写回寄存器文件，但可以直接从 EX/MEM 阶段的 <code>exmem_wb_data</code> 前递过来，这样 <code>sub</code> 就可以立即使用 <code>x3</code> 的值进行计算，而不必等待写回阶段完成。</p><p><strong>普通 ALU 运算冒险主要发生在 EX 阶段，当指令需要使用前一条指令的结果时，如果结果尚未写回寄存器文件，就会产生数据冒险。</strong></p><p>普通数据冒险主要靠 forwarding。</p><p>代码里先定义了四组比较：</p><p><code>ex_match_rs1_exmem</code><code>ex_match_rs1_memwb</code><code>ex_match_rs2_exmem</code><code>ex_match_rs2_memwb</code></p><p>这些信号用于判断：</p><p>当前 EX 阶段要用的 rs1/rs2， 是不是等于后面 EX/MEM 或 MEM/WB 阶段即将写回的 rd。</p><p>相关信号定义在 EX 级 forwarding 区。</p><p>判断是否可以前递：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>assign exmem_can_forward = exmem_rf_we &amp;&amp; (exmem_rd != 5&#39;h0) &amp;&amp; (exmem_wb_sel != WB_SRC_MEM);</span></span>\n<span class="line"><span>assign memwb_can_forward = memwb_rf_we &amp;&amp; (memwb_rd != 5&#39;h0);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这句话的意思是：</p><p>EX/MEM 可以前递：</p><ul><li>必须会写寄存器</li><li>rd 不能是 x0</li><li>不能是 load，因为 load 数据此时还没回来</li></ul><p>MEM/WB 可以前递：</p><ul><li>只要会写寄存器且 rd 不是 x0</li></ul><p>然后根据命中结果决定 ex_rs1_val / ex_rs2_val：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ex_rs1_val = idex_rs1_val;</span></span>\n<span class="line"><span>if (ex_fwd_rs1_from_exmem) begin</span></span>\n<span class="line"><span>    ex_rs1_val = exmem_wb_data;</span></span>\n<span class="line"><span>end else if (ex_fwd_rs1_from_memwb) begin</span></span>\n<span class="line"><span>    ex_rs1_val = memwb_wdata;</span></span>\n<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>rs2 同理。</p><p>sub 到 EX 阶段时，x3 可以直接从 <code>exmem_wb_data</code> 前递过来。</p><h3 id="id-阶段同拍旁路-mem-wb-→-id" tabindex="-1">ID 阶段同拍旁路：MEM/WB → ID <a class="header-anchor" href="#id-阶段同拍旁路-mem-wb-→-id" aria-label="Permalink to &quot;ID 阶段同拍旁路：MEM/WB → ID&quot;">​</a></h3><p>除了 EX forwarding，ID 阶段还有一个小旁路：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if (id_rs1 == 5&#39;d0) begin</span></span>\n<span class="line"><span>    id_rs1_val = 32&#39;h0;// x0 永远是 0</span></span>\n<span class="line"><span>end else if (memwb_can_forward &amp;&amp; (memwb_rd == id_rs1)) begin</span></span>\n<span class="line"><span>    id_rs1_val = memwb_wdata;// MEM/WB → ID 旁路</span></span>\n<span class="line"><span>end else begin</span></span>\n<span class="line"><span>    id_rs1_val = rf_rs1_raw;// 正常读寄存器堆</span></span>\n<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>rs2 也一样。</p><p>它解决的是这种情况：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x3, x1, x2</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">nop</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">nop</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">sub</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x4, x3, x5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>当第一条指令正在 WB 写回时，ID 阶段直接拿 memwb_wdata，避免因为寄存器堆读写同拍顺序不确定导致读到旧值。</p><h3 id="load-use-冒险" tabindex="-1">Load-use 冒险 <a class="header-anchor" href="#load-use-冒险" aria-label="Permalink to &quot;Load-use 冒险&quot;">​</a></h3><p><strong>Load-use 冒险主要发生在 EX 阶段，当一条指令需要使用前一条 load 指令的结果时，如果结果尚未从数据存储器中读取出来，就会产生数据冒险。</strong></p><p>load 比普通 ALU 麻烦，因为 load 的数据要到 MEM/WB 附近才有效，EX/MEM 阶段还拿不到正确数据，所以不能像 ALU 一样直接前递。</p><p>典型例子：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lw  x3, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x1)</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x4, x3, x5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>add 下一拍就要用 x3，但 lw 的数据还没从 perip_rdata 回来，所以必须停。</p><p>代码里检测 load-use：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>assign load_use_hazard = ifid_valid &amp;&amp; idex_valid &amp;&amp; idex_rf_we &amp;&amp;</span></span>\n<span class="line"><span>                         (idex_wb_sel == WB_SRC_MEM) &amp;&amp; (idex_rd != 5&#39;h0) &amp;&amp;</span></span>\n<span class="line"><span>                         ((id_uses_rs1 &amp;&amp; (id_rs1 == idex_rd)) ||</span></span>\n<span class="line"><span>                          (id_uses_rs2 &amp;&amp; (id_rs2 == idex_rd)));</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>翻译一下：</p><ul><li>ID/EX 里是一条 load；</li><li>它会写 rd；</li><li>当前 IF/ID 这条指令要用 rs1 或 rs2；</li><li>并且 rs1/rs2 等于 load 的 rd；</li><li>那么就产生 load_use_hazard。</li></ul><p>处理方式是：</p><ul><li>PC 保持</li><li>IF/ID 保持</li><li>ID/EX 插 bubble</li></ul><p>PC 保持在这里：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>else if (load_use_hazard || pc_ex_hazard || pc_mem_hazard || mem_load_stall || m_stall) begin</span></span>\n<span class="line"><span>    pc_next = pc_q;</span></span>\n<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>IF/ID 保持在这里：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>else if (load_use_hazard || pc_ex_hazard || pc_mem_hazard || mem_load_stall || m_stall) begin</span></span>\n<span class="line"><span>    ifid_pc    &lt;= ifid_pc;</span></span>\n<span class="line"><span>    ifid_instr &lt;= ifid_instr;</span></span>\n<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>else if (!load_use_hazard &amp;&amp; !pc_ex_hazard &amp;&amp; !pc_mem_hazard &amp;&amp; !mem_load_stall &amp;&amp; !m_stall) begin ifid_pc &lt;= pc_q; ifid_instr &lt;= irom_data; end</p><p>ID/EX 插 bubble 在这里：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>else if (ex_pc_redirect || load_use_hazard || pc_ex_hazard || pc_mem_hazard) begin</span></span>\n<span class="line"><span>    idex_valid &lt;= 1&#39;b0;</span></span>\n<span class="line"><span>    ...</span></span>\n<span class="line"><span>    idex_rf_we &lt;= 1&#39;b0;</span></span>\n<span class="line"><span>    idex_mem_req &lt;= 1&#39;b0;</span></span>\n<span class="line"><span>    idex_is_m_ext &lt;= 1&#39;b0;</span></span>\n<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这就是经典的：<strong><code>load-use stall</code> 一拍 + 插入空泡</strong></p><h3 id="mem-load-stall" tabindex="-1">MEM load stall <a class="header-anchor" href="#mem-load-stall" aria-label="Permalink to &quot;MEM load stall&quot;">​</a></h3><p>这个工程里，DRAM/MMIO 读数据不是立刻回来，而是统一打一拍。所以只要 EX/MEM 阶段是 load，就要额外等一拍。</p><p>代码：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>assign mem_load_stall = exmem_valid &amp;&amp; exmem_mem_req &amp;&amp; !exmem_mem_write &amp;&amp; !mem_stall_flag;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>意思是：</p><ul><li>EX/MEM 是有效访存；</li><li>它是 load，不是 store；</li><li>而且这一拍还没 stall 过；</li><li>那么 mem_load_stall = 1。</li></ul><p>mem_stall_flag 用来保证每个 load 只额外停一拍，不会无限停。</p><p>处理方式：</p><ul><li>PC hold</li><li>IF/ID hold</li><li>ID/EX hold</li><li>EX/MEM hold</li><li>MEM/WB hold</li></ul><p>其中 ID/EX 在 mem_load_stall 时保持。 MEM/WB 在 mem_load_stall 时也保持旧值，避免错误写回。</p><p>这和 load-use 不一样：</p><p><code>load_use_hazard</code>：为了下一条用 load 结果，插 bubble <code>mem_load_stall</code>：为了等 <code>perip_rdata</code> 稳定，整体 hold 一拍</p><h3 id="branch-jalr-的-pc-操作数冒险-现在选择-等-不前递" tabindex="-1">branch / jalr 的 PC 操作数冒险：现在选择“等”，不前递 <a class="header-anchor" href="#branch-jalr-的-pc-操作数冒险-现在选择-等-不前递" aria-label="Permalink to &quot;branch / jalr 的 PC 操作数冒险：现在选择“等”，不前递&quot;">​</a></h3><p>普通 ALU 可以从 EX/MEM 前递，但 branch/jalr 的 PC 选择链为了提频，不再吃 EXMEM 前递：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>assign ex_pc_fwd_rs1_from_exmem = 1&#39;b0;</span></span>\n<span class="line"><span>assign ex_pc_fwd_rs1_from_memwb = 1&#39;b0;</span></span>\n<span class="line"><span>assign ex_pc_fwd_rs2_from_exmem = 1&#39;b0;</span></span>\n<span class="line"><span>assign ex_pc_fwd_rs2_from_memwb = 1&#39;b0;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>也就是说，分支和 JALR 不再用复杂前递链去抢最新数据，而是在 ID 阶段发现不安全时直接等。</p><p>两个 hazard 定义在这里：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>assign pc_ex_hazard = ifid_valid &amp;&amp; idex_valid &amp;&amp; idex_rf_we &amp;&amp;</span></span>\n<span class="line"><span>                     (idex_wb_sel != WB_SRC_MEM) &amp;&amp; (idex_rd != 5&#39;h0) &amp;&amp;</span></span>\n<span class="line"><span>                     ((((id_pc_sel == PC_SRC_BRANCH) || (id_pc_sel == PC_SRC_JALR)) &amp;&amp; (id_rs1 == idex_rd)) ||</span></span>\n<span class="line"><span>                      ((id_pc_sel == PC_SRC_BRANCH) &amp;&amp; (id_rs2 == idex_rd)));</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>assign pc_mem_hazard = ifid_valid &amp;&amp; exmem_valid &amp;&amp; exmem_rf_we &amp;&amp;</span></span>\n<span class="line"><span>                      (exmem_wb_sel != WB_SRC_MEM) &amp;&amp; (exmem_rd != 5&#39;h0) &amp;&amp;</span></span>\n<span class="line"><span>                      ((((id_pc_sel == PC_SRC_BRANCH) || (id_pc_sel == PC_SRC_JALR)) &amp;&amp; (id_rs1 == exmem_rd)) ||</span></span>\n<span class="line"><span>                       ((id_pc_sel == PC_SRC_BRANCH) &amp;&amp; (id_rs2 == exmem_rd)));</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>翻译一下：</p><p><strong><code>pc_ex_hazard</code></strong>：</p><ul><li>当前 IF/ID 中的指令是 branch 或 jalr（<code>id_pc_sel == PC_SRC_BRANCH/JALR</code>）</li><li>且使用的操作数 rs1 或 rs2（分支用两个，jalr 用 rs1）恰好是 ID/EX 中正在执行的指令的目标寄存器（<code>idex_rd</code>）</li><li>且该寄存器是有效写回的（<code>idex_rf_we &amp;&amp; idex_wb_sel != WB_SRC_MEM</code>）</li><li><strong>问题</strong>：branch/jalr 需要在 EX 阶段就能拿到 rs1/rs2 的值来判断跳转，但这个值还在 ID/EX 中没有计算出来</li><li><strong>产生冒险的条件</strong>：branch/jalr 的 rs1/rs2 等于 ID/EX 的 rd，且 ID/EX 会写回寄存器，且不是 load。</li></ul><p><strong><code>pc_mem_hazard</code></strong>：</p><ul><li>当前 IF/ID 中的指令是 branch 或 jalr</li><li>使用的 rs1 或 rs2 恰好是 EX/MEM 中指令的目标寄存器（<code>exmem_rd</code>）</li><li>且该寄存器是有效写回的</li><li><strong>问题</strong>：值还在 EX/MEM 中，还没有进入 MEM 阶段完成，</li><li><strong>产生冒险的条件</strong>：branch/jalr 的 rs1/rs2 等于 EX/MEM 的 rd，且 EX/MEM 会写回寄存器，且不是 load。</li></ul><p>它解决的是：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x1, x2, x3</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">beq x1, x0, label</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>或者：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x1, x2, x3</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">jalr x0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x1)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这种指令如果不等，branch/jalr 在 EX 阶段可能拿旧 x1 算跳转结果。</p><p>现在处理方式是：</p><p><code>pc_ex_hazard</code> 或 <code>pc_mem_hazard</code> 出现：</p><ul><li>PC hold</li><li>IF/ID hold</li><li>ID/EX 插 bubble</li></ul><p>PC hold 在 PC 更新逻辑里。 IF/ID valid 也在 <code>pc_ex_hazard || pc_mem_hazard</code> 时保持。 ID/EX 在这两个 hazard 时清 bubble。</p><p>普通 ALU 数据冒险：前递 分支/jalr 的 PC 数据冒险：等待</p><p>这是为了缩短 PC redirect 关键路径。</p><h3 id="m-扩展多周期冒险-m-stall" tabindex="-1">M 扩展多周期冒险：m_stall <a class="header-anchor" href="#m-扩展多周期冒险-m-stall" aria-label="Permalink to &quot;M 扩展多周期冒险：m_stall&quot;">​</a></h3><p>新版代码把 M 扩展做成了一个小状态机：</p><ul><li>m_inflight：M 指令正在执行</li><li>m_result_ready：M 指令结果已经准备好</li><li>m_stall：当前 ID/EX 是 M 指令但结果还没好</li></ul><p>相关信号在 EX 级定义区。</p><p>启动逻辑：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>assign m_start = idex_valid &amp;&amp; idex_is_m_ext &amp;&amp; !m_inflight &amp;&amp; !m_result_ready &amp;&amp; !ex_pc_redirect;</span></span>\n<span class="line"><span>assign mul_start = m_start &amp;&amp; ex_m_is_mul;</span></span>\n<span class="line"><span>assign div_start = m_inflight &amp;&amp; m_is_div_reg &amp;&amp; !m_div_started;</span></span>\n<span class="line"><span>assign m_stall = idex_valid &amp;&amp; idex_is_m_ext &amp;&amp; !m_result_ready;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>意思是：</p><p>M 指令进入 EX 后，先启动 M 状态机； 结果没好之前，m_stall=1； m_stall=1 时 PC/IFID/IDEX hold； EX/MEM 插 bubble； 结果好了后，放行一拍，把 ex_m_result 写入后级。</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>//PC hold：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>else if (load_use_hazard || pc_ex_hazard || pc_mem_hazard || mem_load_stall || m_stall) begin</span></span>\n<span class="line"><span>    pc_next = pc_q;</span></span>\n<span class="line"><span>end</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>//IF/ID hold：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>else if (!load_use_hazard &amp;&amp; !pc_ex_hazard &amp;&amp; !pc_mem_hazard &amp;&amp; !mem_load_stall &amp;&amp; !m_stall) begin</span></span>\n<span class="line"><span>    ifid_pc    &lt;= pc_q;</span></span>\n<span class="line"><span>    ifid_instr &lt;= irom_data;</span></span>\n<span class="line"><span>end</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>//ID/EX hold：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>else if (mem_load_stall || m_stall) begin</span></span>\n<span class="line"><span>    // hold IDEX</span></span>\n<span class="line"><span>end</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>//EX/MEM 在 m_stall 时清 bubble：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>else if (m_stall) begin</span></span>\n<span class="line"><span>    exmem_valid &lt;= 1&#39;b0;</span></span>\n<span class="line"><span>    exmem_rf_we &lt;= 1&#39;b0;</span></span>\n<span class="line"><span>    exmem_mem_req &lt;= 1&#39;b0;</span></span>\n<span class="line"><span>    ...</span></span>\n<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br></div></div><p>M 指令在 EX 等结果时，后级不能反复收到同一条指令，所以 EX/MEM 要清空。</p><h3 id="store-数据冒险" tabindex="-1">store 数据冒险 <a class="header-anchor" href="#store-数据冒险" aria-label="Permalink to &quot;store 数据冒险&quot;">​</a></h3><p>store 有两个源：</p><p>rs1：地址基址 rs2：要写入内存的数据</p><p>代码里 <code>id_uses_rs2 = 1</code>，所以 store 的 rs2 也会参与 forwarding/hazard 判断。</p><p>EX 阶段 store 数据来自：</p><div class="language-SystemVerilog vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SystemVerilog</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>assign ex_store_data = idex_mem_write ? ex_rs2_val : 32&#39;h0;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>而 <code>ex_rs2_val</code> 已经经过 EX forwarding，所以这种情况一般不用停。</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x3, x1, x2</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sw  x3, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x4)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>sw 到 EX 阶段时，写入数据 x3 可以从 EX/MEM 或 MEM/WB 前递得到。</p><p>但如果是：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lw x3, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x1)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sw x3, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x4)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这仍会被 <code>load_use_hazard</code> 检测到，因为 store 使用 rs2，且 load 的 rd 等于 store 的 rs2。</p><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h3><div class="table-container"><table><thead><tr><th>冒险类型</th><th>例子</th><th>处理方法</th><th>代码位置</th></tr></thead><tbody><tr><td>普通 ALU 数据冒险</td><td><code>add x3,...</code> 后接 <code>sub x4,x3,...</code></td><td>EX/MEM 或 MEM/WB forwarding</td><td><code>ex_fwd_rs*_from_*</code> 和 <code>ex_rs*_val</code></td></tr><tr><td>WB 同拍读冒险</td><td>WB 写 x3，ID 同拍读 x3</td><td>MEM/WB → ID 旁路</td><td><code>id_rs1_val/id_rs2_val</code></td></tr><tr><td>load-use 冒险</td><td><code>lw x3,...</code> 后接 <code>add ...,x3,...</code></td><td>PC/IFID hold，IDEX bubble</td><td><code>load_use_hazard</code></td></tr><tr><td>load 读延迟</td><td>任意 load</td><td><code>mem_load_stall</code> 额外等一拍</td><td><code>mem_load_stall/mem_stall_flag</code></td></tr><tr><td>branch/jalr 操作数冒险</td><td><code>add x1,...</code> 后接 <code>beq x1,...</code></td><td>不走 PC 前递，等待数据稳定</td><td><code>pc_ex_hazard/pc_mem_hazard</code></td></tr><tr><td>控制冒险</td><td>branch taken / jal / jalr / ecall / mret</td><td><code>ex_pc_redirect</code> + flush</td><td><code>ex_pc_target/ex_pc_redirect</code></td></tr><tr><td>M 扩展多周期冒险</td><td><code>mul/div/rem</code></td><td><code>m_stall</code> hold 前级，EX/MEM bubble</td><td><code>m_start/m_inflight/m_result_ready/m_stall</code></td></tr></tbody></table></div>',202)]))}]]);export{p as __pageData,l as default};
